'use client'

import { ESTACOES_JORNADA } from '@/data/jornada-estacoes'
import { FASES } from '@/types/jornada'
import { PROMPT_CONFIGS, type PromptType } from '@/types/prompt'
import { CopyButton } from '@/components/shared/copy-button'
import { useProfile } from '@/hooks/use-profile'
import { motion, AnimatePresence } from 'framer-motion'
import { useState, useEffect, useMemo } from 'react'
import Link from 'next/link'

const STORAGE_KEY = 'jornada-completed'

function loadCompleted(): Set<number> {
  if (typeof window === 'undefined') return new Set()
  try {
    const raw = localStorage.getItem(STORAGE_KEY)
    if (raw) return new Set(JSON.parse(raw))
  } catch { /* ignore */ }
  return new Set()
}

function saveCompleted(set: Set<number>) {
  localStorage.setItem(STORAGE_KEY, JSON.stringify([...set]))
}

/** Map promptTipo to the profile response field */
const PROMPT_RESPONSE_MAP: Record<PromptType, string> = {
  clareza: 'resposta1',
  persona: 'resposta2',
  ideias: 'resposta3',
  roteiro: 'resposta4',
  vendas: 'resposta5',
}

export default function JornadaPage() {
  const [expanded, setExpanded] = useState<number | null>(null)
  const [completed, setCompleted] = useState<Set<number>>(new Set())
  const { profile } = useProfile()

  useEffect(() => {
    setCompleted(loadCompleted())
  }, [])

  // Auto-completed stations based on prompt responses
  const autoCompleted = useMemo(() => {
    if (!profile) return new Set<number>()
    const auto = new Set<number>()
    ESTACOES_JORNADA.forEach(est => {
      if (est.promptTipo) {
        const field = PROMPT_RESPONSE_MAP[est.promptTipo]
        const value = (profile as Record<string, string | null>)?.[field]
        if (value && value.trim().length > 0) {
          auto.add(est.id)
        }
      }
    })
    return auto
  }, [profile])

  const toggleCompleted = (id: number) => {
    setCompleted(prev => {
      const next = new Set(prev)
      if (next.has(id)) next.delete(id)
      else next.add(id)
      saveCompleted(next)
      return next
    })
  }

  const total = ESTACOES_JORNADA.length
  const allDone = new Set([...completed, ...autoCompleted])
  const done = allDone.size
  const progress = total > 0 ? Math.round((done / total) * 100) : 0

  return (
    <>
      <main className="flex-1 flex flex-col overflow-y-auto overflow-x-hidden relative z-10 custom-scrollbar">
        <div className="p-6 lg:p-12 max-w-5xl mx-auto w-full space-y-16">

          {/* Welcome/Title Banner */}
          <section className="text-center space-y-4 relative z-10">
            <motion.h1 initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="text-4xl lg:text-5xl font-black text-white tracking-tighter uppercase italic">
              <span className="text-transparent bg-clip-text bg-gradient-to-r from-sky-400 to-[#0ea5e9]">JORNADA DE</span> CONTEÚDO
            </motion.h1>
            <motion.p initial={{ opacity: 0 }} animate={{ opacity: 1 }} transition={{ delay: 0.1 }} className="text-slate-400 text-lg max-w-2xl mx-auto leading-relaxed">
              Siga o mapa metodológico. Cada estação contém uma dica prática para aplicar imediatamente e um prompt para usar com o Gerador.
            </motion.p>

            {/* Progress Bar */}
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.15 }} className="max-w-md mx-auto pt-4">
              <div className="flex justify-between items-end mb-2">
                <span className="text-xs font-bold uppercase tracking-widest text-[#0ea5e9]">Progresso da Jornada</span>
                <span className="text-xs font-medium text-slate-400">{done} / {total} estações</span>
              </div>
              <div className="h-2 w-full bg-white/10 rounded-full overflow-hidden">
                <motion.div 
                  className="h-full bg-gradient-to-r from-sky-400 to-[#0ea5e9] rounded-full" 
                  initial={{ width: 0 }}
                  animate={{ width: `${Math.max(progress, 1)}%` }}
                  transition={{ duration: 1, ease: [0.16, 1, 0.3, 1] }}
                />
              </div>
              <p className="text-xs text-slate-500 mt-1.5 text-right font-semibold">{progress}%</p>
            </motion.div>
          </section>

          {/* Phase Filters/Indicators */}
          <motion.div initial={{ opacity: 0, y: 20 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.2 }} className="flex flex-wrap items-center justify-center gap-3">
             {FASES.map(f => (
               <div key={f.numero} className="flex items-center gap-2 text-xs text-slate-300 bg-white/5 py-2 px-4 rounded-full border border-white/10 glass-card">
                 <span className="text-sm">{f.icone}</span>
                 <span className="font-bold tracking-widest uppercase">{f.nome}</span>
               </div>
             ))}
          </motion.div>

          {/* Stations Timeline */}
          <section className="relative space-y-6 pb-20">
            {/* Context Line */}
            <div className="absolute left-[39px] top-8 bottom-8 w-px bg-gradient-to-b from-[#0ea5e9]/50 via-[#0ea5e9]/10 to-transparent hidden md:block" />

            {ESTACOES_JORNADA.map((est, i) => {
              const isExpanded = expanded === est.id
              const fase = FASES.find(f => f.numero === est.fase)
              const isManualDone = completed.has(est.id)
              const isAutoDone = autoCompleted.has(est.id)
              const isDone = isManualDone || isAutoDone

              return (
                <motion.div
                  key={est.id}
                  initial={{ opacity: 0, x: -20 }}
                  animate={{ opacity: 1, x: 0 }}
                  transition={{ duration: 0.4, delay: Math.min(i * 0.05, 0.4) }}
                  className="relative group"
                >
                  {/* Connecting Dot */}
                  <div className={`absolute left-[35px] top-10 size-[9px] rounded-full hidden md:block z-10 transition-colors duration-500 ${isDone ? 'bg-emerald-400 shadow-[0_0_15px_rgba(52,211,153,0.8)] scale-150' : isExpanded ? 'bg-[#0ea5e9] shadow-[0_0_15px_rgba(14,165,233,0.8)] scale-150' : est.marco ? 'bg-amber-400 shadow-[0_0_15px_rgba(251,191,36,0.5)]' : 'bg-[#0ea5e9]/30'}`} />

                  <div className={`glass-card rounded-2xl overflow-hidden transition-all duration-300 md:ml-16 relative ${isDone ? 'border-emerald-500/20 bg-emerald-500/[0.02]' : isExpanded ? 'border-[#0ea5e9]/30 bg-white/[0.03]' : est.marco ? 'border-amber-500/20 bg-amber-500/[0.02]' : 'border-white/5 hover:border-white/10'}`}>

                    {/* Hover Glow */}
                    <div className="absolute inset-0 bg-gradient-to-br from-[#0ea5e9]/5 to-transparent opacity-0 group-hover:opacity-100 transition-opacity pointer-events-none" />

                    <button
                      onClick={() => setExpanded(isExpanded ? null : est.id)}
                      className="w-full flex items-center md:items-start gap-5 p-6 text-left relative z-10 focus:outline-none"
                    >
                      <div className={`size-14 rounded-xl flex items-center justify-center text-2xl shrink-0 transition-colors shadow-inner ${isDone ? 'bg-gradient-to-br from-emerald-400/20 to-green-500/20 text-emerald-400 border border-emerald-500/30' : est.marco ? 'bg-gradient-to-br from-amber-400/20 to-orange-500/20 text-amber-400 border border-amber-500/30' : 'bg-black/40 text-slate-300 border border-white/10 group-hover:bg-[#0ea5e9]/10 group-hover:text-[#0ea5e9]'}`}>
                        {isDone ? (
                          <span className="material-symbols-outlined text-3xl text-emerald-400">check_circle</span>
                        ) : est.icone}
                      </div>

                      <div className="flex-1 min-w-0 md:pt-1">
                        <div className="flex flex-wrap items-center gap-3 mb-2">
                          <span className="text-[10px] text-[#0ea5e9] bg-[#0ea5e9]/10 px-2.5 py-1 rounded font-black tracking-widest uppercase">
                            #{est.id.toString().padStart(2, '0')}
                          </span>
                          <h3 className={`font-bold text-xl truncate tracking-tight ${isDone ? 'text-emerald-400 line-through decoration-emerald-400/30' : 'text-white'}`}>{est.nome}</h3>
                          {isAutoDone && !isManualDone && (
                            <span className="bg-violet-500/20 text-violet-400 text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded flex items-center gap-1">
                              <span className="material-symbols-outlined text-[12px]">auto_awesome</span>
                              Via Gerador
                            </span>
                          )}
                          {isManualDone && (
                            <span className="bg-emerald-500/20 text-emerald-400 text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded flex items-center gap-1">
                              <span className="material-symbols-outlined text-[12px]">done</span>
                              Concluída
                            </span>
                          )}
                          {est.marco && !isDone && (
                            <span className="bg-gradient-to-r from-amber-500 to-orange-500 text-white text-[10px] font-black uppercase tracking-widest px-2.5 py-1 rounded flex items-center gap-1 shadow-lg shadow-amber-500/20">
                              <span className="material-symbols-outlined text-[12px]">star</span>
                              Marco
                            </span>
                          )}
                        </div>
                        <p className="text-sm text-slate-400 line-clamp-2 md:line-clamp-1 leading-relaxed">{est.descricao}</p>
                      </div>

                      <div className="shrink-0 self-center md:self-start mt-2 md:mt-4">
                        <div className={`size-8 rounded-full flex items-center justify-center transition-colors ${isExpanded ? 'bg-[#0ea5e9] text-white' : 'glass-card text-slate-400 group-hover:text-white'}`}>
                          <span className={`material-symbols-outlined transition-transform duration-300 ${isExpanded ? 'rotate-180' : ''}`}>
                             expand_more
                          </span>
                        </div>
                      </div>
                    </button>

                    <AnimatePresence>
                      {isExpanded && (
                        <motion.div 
                          initial={{ height: 0, opacity: 0 }} 
                          animate={{ height: 'auto', opacity: 1 }} 
                          exit={{ height: 0, opacity: 0 }}
                          className="overflow-hidden relative z-10"
                        >
                          <div className="border-t border-white/10 p-6 md:p-8 space-y-6 bg-black/40 backdrop-blur-md">

                            {/* Phase Indicator */}
                            <div className="flex items-center gap-2 text-xs text-slate-400 bg-white/5 inline-flex px-3 py-1.5 rounded-md border border-white/5">
                              <span className="material-symbols-outlined text-[14px] text-[#0ea5e9]">trip_origin</span>
                              <span className="font-medium uppercase tracking-widest">Fase {est.fase}: <span className="text-white font-bold">{fase?.nome}</span></span>
                            </div>

                            {/* Practical Tip Card */}
                            <div className="rounded-xl bg-gradient-to-br from-[#0ea5e9]/5 to-violet-500/5 border border-[#0ea5e9]/20 p-6">
                              <div className="flex items-center gap-2 mb-4">
                                <span className="material-symbols-outlined text-[#0ea5e9] text-xl">lightbulb</span>
                                <h4 className="text-sm font-black text-[#0ea5e9] uppercase tracking-widest">Dica Prática</h4>
                              </div>
                              <pre className="text-[14px] text-slate-300 whitespace-pre-wrap leading-relaxed font-sans">
                                {est.dica}
                              </pre>
                            </div>

                            {/* Terminal Sandbox */}
                            <div className="rounded-xl overflow-hidden border border-white/10 bg-[#000000] shadow-2xl relative group/terminal">
                              <div className="flex items-center px-4 py-3 border-b border-white/10 bg-white/[0.02]">
                                <div className="flex gap-2">
                                  <div className="w-3 h-3 rounded-full bg-red-500/80" />
                                  <div className="w-3 h-3 rounded-full bg-amber-500/80" />
                                  <div className="w-3 h-3 rounded-full bg-green-500/80" />
                                </div>
                                <span className="ml-4 text-xs font-mono text-slate-500">prompt_estacao_{est.id.toString().padStart(2, '0')}.md</span>
                                <div className="ml-auto opacity-0 group-hover/terminal:opacity-100 transition-opacity">
                                  <CopyButton text={est.prompt} />
                                </div>
                              </div>
                              <div className="p-6 overflow-x-auto relative">
                                <pre className="text-[14px] font-mono text-[#0ea5e9] whitespace-pre-wrap leading-relaxed">
                                  {est.prompt}
                                </pre>
                              </div>
                            </div>

                            {/* Action Buttons */}
                            <div className="flex flex-col sm:flex-row gap-3">
                              {est.promptTipo && (
                                <Link
                                  href={`/prompts/${est.promptTipo}`}
                                  className="flex-1 flex items-center justify-center gap-3 py-4 rounded-xl font-bold text-sm uppercase tracking-widest bg-gradient-to-r from-violet-500 to-purple-600 text-white shadow-lg shadow-violet-500/20 hover:shadow-violet-500/40 transition-all active:scale-[0.98]"
                                >
                                  <span className="material-symbols-outlined text-xl">magic_button</span>
                                  <span>Abrir {PROMPT_CONFIGS[est.promptTipo].titulo}</span>
                                </Link>
                              )}
                              <button
                                onClick={() => toggleCompleted(est.id)}
                                className={`flex-1 flex items-center justify-center gap-3 py-4 rounded-xl font-bold text-sm uppercase tracking-widest transition-all active:scale-[0.98] ${
                                  isDone 
                                    ? 'bg-emerald-500/10 text-emerald-400 border border-emerald-500/30 hover:bg-emerald-500/20' 
                                    : 'bg-white/5 text-white border border-white/10 hover:bg-white/10'
                                }`}
                              >
                                <span className="material-symbols-outlined text-xl">
                                  {isDone ? 'undo' : 'check_circle'}
                                </span>
                                <span>{isDone ? 'Desfazer' : 'Concluída'}</span>
                              </button>
                            </div>

                          </div>
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </div>
                </motion.div>
              )
            })}
          </section>

        </div>
      </main>
    </>
  )
}

'use client'

import { useState, useRef } from 'react'

import { useProfile } from '@/hooks/use-profile'
import { useAutoSave } from '@/hooks/use-auto-save'
import { PROFILE_FIELDS } from '@/types/profile'
import { Input } from '@/components/ui/input'
import { Textarea } from '@/components/ui/textarea'
import { motion, AnimatePresence } from 'framer-motion'
import { CheckCircle2, Loader2 } from 'lucide-react'
import Link from 'next/link'

const SECTION_META = {
  sobre: { icon: 'person', title: 'Sobre Você', desc: 'Conta um pouco sobre o que você faz' },
  publico: { icon: 'groups', title: 'Seu Público', desc: 'Quem são as pessoas que você quer alcançar' },
  objetivos: { icon: 'rocket_launch', title: 'Seus Objetivos', desc: 'O que você quer conseguir' },
}

export default function PerfilPage() {
  const { profile, loading, userId, updateField, uploadAvatar, getCompletionPercent } = useProfile()
  const { debouncedSave } = useAutoSave(userId)
  const [saveStatus, setSaveStatus] = useState<Record<string, 'idle' | 'saving' | 'saved' | 'error'>>({})
  const [editingName, setEditingName] = useState(false)
  const [tempName, setTempName] = useState('')
  const [uploadingAvatar, setUploadingAvatar] = useState(false)
  const [enhancingAll, setEnhancingAll] = useState(false)
  const [enhanceResult, setEnhanceResult] = useState<'idle' | 'success' | 'error'>('idle')
  const fileInputRef = useRef<HTMLInputElement>(null)

  const completion = getCompletionPercent()

  const handleFieldChange = (fieldId: string, value: string) => {
    updateField(fieldId, value)
    debouncedSave(fieldId, value, (status) => {
      setSaveStatus(prev => ({ ...prev, [fieldId]: status === 'saving' ? 'saving' : status === 'saved' ? 'saved' : 'error' }))
      if (status === 'saved') {
        setTimeout(() => setSaveStatus(prev => ({ ...prev, [fieldId]: 'idle' })), 2000)
      }
    })
  }

  const getDisplayName = () => {
    if (profile?.nome_completo) return profile.nome_completo
    if (!profile?.email) return 'Usuário Mapeador'
    return profile.email.split('@')[0].split('.')[0].replace(/^\w/, c => c.toUpperCase())
  }

  const getInitials = () => {
    const name = profile?.nome_completo || profile?.email?.split('@')[0] || 'U'
    const parts = name.split(/[\s.]+/)
    if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase()
    return name.substring(0, 2).toUpperCase()
  }

  const handleAvatarClick = () => {
    fileInputRef.current?.click()
  }

  const handleAvatarChange = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return
    setUploadingAvatar(true)
    await uploadAvatar(file)
    setUploadingAvatar(false)
    // Reset input so same file can be re-selected
    if (fileInputRef.current) fileInputRef.current.value = ''
  }

  const handleStartEditName = () => {
    setTempName(profile?.nome_completo || getDisplayName())
    setEditingName(true)
  }

  const handleSaveName = () => {
    if (tempName.trim()) {
      handleFieldChange('nome_completo', tempName.trim())
    }
    setEditingName(false)
  }

  const handleCancelEditName = () => {
    setEditingName(false)
  }

  const handleEnhanceAll = async () => {
    if (!profile) return
    setEnhanceResult('idle')

    const filledFields = PROFILE_FIELDS
      .filter(f => {
        const val = (profile as Record<string, string | null>)?.[f.id]
        return val && val.trim().length >= 5
      })
      .map(f => ({
        id: f.id,
        label: f.label,
        value: (profile as Record<string, string | null>)?.[f.id] || '',
      }))

    if (filledFields.length === 0) return

    setEnhancingAll(true)
    try {
      const res = await fetch('/api/enhance-answer', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ fields: filledFields }),
      })
      const data = await res.json()
      console.log('[AI Enhance] Response:', JSON.stringify(data).substring(0, 500))

      if (data.enhanced && typeof data.enhanced === 'object') {
        let updated = 0
        for (const [fieldId, value] of Object.entries(data.enhanced)) {
          if (typeof value === 'string' && value.trim().length > 0) {
            const original = filledFields.find(f => f.id === fieldId)?.value
            // Only update if value actually changed
            if (original !== value) {
              handleFieldChange(fieldId, value)
              updated++
            }
          }
        }
        console.log('[AI Enhance] Updated fields:', updated, 'used_ai:', data.used_ai)
        setEnhanceResult(updated > 0 ? 'success' : data.used_ai ? 'success' : 'error')
      } else {
        console.error('[AI Enhance] No enhanced data in response:', data)
        setEnhanceResult('error')
      }
    } catch (err) {
      console.error('[AI Enhance] Fetch error:', err)
      setEnhanceResult('error')
    }
    setEnhancingAll(false)
    setTimeout(() => setEnhanceResult('idle'), 4000)
  }

  if (loading) {
    return (
      <>
        <div className="flex items-center justify-center h-96 relative z-10 w-full">
          <Loader2 className="w-8 h-8 animate-spin text-[#0ea5e9]" />
        </div>
      </>
    )
  }

  const sections = ['sobre', 'publico', 'objetivos'] as const

  return (
    <>
      <main className="flex-1 flex flex-col items-center w-full relative z-10 overflow-y-auto custom-scrollbar">
        <div className="w-full max-w-7xl px-6 lg:px-8 py-8 md:py-12 pb-24">

          {/* Profile Header — Clean, no cover */}
          <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="mb-12">
            <div className="flex flex-col md:flex-row items-center md:items-end gap-6 text-center md:text-left">
              {/* Avatar with Upload */}
              <div className="relative group">
                <div 
                  className="size-28 rounded-full border-4 border-white/10 p-0.5 glass-card shadow-[0_0_30px_rgba(14,165,233,0.2)] bg-black/50 cursor-pointer overflow-hidden"
                  onClick={handleAvatarClick}
                >
                  {profile?.avatar_url ? (
                    <img 
                      src={profile.avatar_url} 
                      alt="Avatar" 
                      className="w-full h-full rounded-full object-cover"
                    />
                  ) : (
                    <div className="w-full h-full rounded-full bg-gradient-to-tr from-[#0ea5e9] to-indigo-500 flex items-center justify-center">
                      <span className="text-3xl font-black text-white">{getInitials()}</span>
                    </div>
                  )}
                </div>
                {/* Upload overlay */}
                <div 
                  className="absolute inset-0 rounded-full bg-black/60 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity cursor-pointer"
                  onClick={handleAvatarClick}
                >
                  {uploadingAvatar ? (
                    <Loader2 className="w-6 h-6 animate-spin text-white" />
                  ) : (
                    <span className="material-symbols-outlined text-white text-2xl">photo_camera</span>
                  )}
                </div>
                <input
                  ref={fileInputRef}
                  type="file"
                  accept="image/png,image/jpeg,image/webp"
                  className="hidden"
                  onChange={handleAvatarChange}
                />
              </div>

              {/* Name & Email */}
              <div className="mb-2 md:mb-4">
                {editingName ? (
                  <div className="flex items-center gap-2">
                    <input
                      type="text"
                      value={tempName}
                      onChange={(e) => setTempName(e.target.value)}
                      onKeyDown={(e) => { if (e.key === 'Enter') handleSaveName(); if (e.key === 'Escape') handleCancelEditName() }}
                      autoFocus
                      className="text-2xl font-black text-white tracking-tight bg-white/5 border border-white/20 rounded-xl px-4 py-2 focus:outline-none focus:border-[#0ea5e9] transition-all"
                    />
                    <button onClick={handleSaveName} className="text-[#0ea5e9] hover:text-white transition-colors">
                      <span className="material-symbols-outlined">check</span>
                    </button>
                    <button onClick={handleCancelEditName} className="text-slate-500 hover:text-white transition-colors">
                      <span className="material-symbols-outlined">close</span>
                    </button>
                  </div>
                ) : (
                  <div className="flex items-center gap-3 group cursor-pointer" onClick={handleStartEditName}>
                    <h2 className="text-3xl font-black text-white tracking-tight">{getDisplayName()}</h2>
                    <span className="material-symbols-outlined text-slate-600 opacity-0 group-hover:opacity-100 transition-opacity text-lg">edit</span>
                  </div>
                )}
                <p className="text-[#0ea5e9] font-medium tracking-wide text-sm mt-1">{profile?.email}</p>
              </div>
            </div>
          </motion.div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-8">
            {/* Left Side: Form Fields */}
            <div className="lg:col-span-8 space-y-8">

              {/* Progress Card */}
              <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} transition={{ delay: 0.1 }} className="glass-card rounded-3xl p-8 border border-white/5 relative overflow-hidden group">
                 <div className="absolute top-0 right-0 p-6 opacity-5 group-hover:opacity-10 transition-opacity">
                    <span className="material-symbols-outlined text-[80px] text-[#0ea5e9]">verified</span>
                 </div>
                 <div className="relative z-10 flex flex-col md:flex-row md:items-center justify-between gap-6">
                    <div>
                      <h3 className="text-xl font-bold text-white mb-2">Suas Informações</h3>
                      <p className="text-sm text-slate-400 max-w-md">
                        {completion < 50 ? 'Responda as perguntas abaixo para a gente te conhecer melhor. É com base nisso que vamos criar todos os seus textos e roteiros.' :
                         completion < 100 ? 'Quase lá! Faltam só alguns detalhes para a gente te ajudar melhor.' :
                         'Tudo preenchido! Agora seus textos e roteiros vão ser feitos sob medida para você.'}
                      </p>
                    </div>
                    <div className="flex items-center gap-4 shrink-0">
                       <div className="text-right">
                          <span className="block text-3xl font-black text-white">{completion}%</span>
                          <span className="text-[10px] font-bold text-[#0ea5e9] uppercase tracking-widest">Concluído</span>
                       </div>
                    </div>
                 </div>
                 <div className="w-full h-2 bg-white/5 rounded-full mt-6 overflow-hidden relative z-10">
                    <div 
                      className="h-full bg-gradient-to-r from-sky-400 to-[#0ea5e9] shadow-[0_0_15px_rgba(14,165,233,0.5)] transition-all duration-1000 ease-[cubic-bezier(0.16,1,0.3,1)]"
                      style={{ width: `${completion}%` }}
                    />
                 </div>

                 {/* Single AI Enhance Button */}
                 {completion > 0 && (
                   <motion.button
                     initial={{ opacity: 0 }}
                     animate={{ opacity: 1 }}
                     onClick={handleEnhanceAll}
                     disabled={enhancingAll}
                     className={`mt-6 w-full py-3.5 rounded-2xl flex items-center justify-center gap-3 text-sm font-bold transition-all active:scale-[0.98] relative z-10 border disabled:opacity-60 disabled:pointer-events-none ${
                       enhanceResult === 'success'
                         ? 'border-emerald-500/30 bg-emerald-500/10 text-emerald-300'
                         : enhanceResult === 'error'
                         ? 'border-red-500/30 bg-red-500/10 text-red-300'
                         : 'border-violet-500/30 bg-violet-500/10 text-violet-300 hover:bg-violet-500/20 hover:border-violet-500/50'
                     }`}
                   >
                     {enhancingAll ? (
                       <>
                         <Loader2 className="w-4 h-4 animate-spin" />
                         <span>Melhorando respostas...</span>
                       </>
                     ) : enhanceResult === 'success' ? (
                       <>
                         <CheckCircle2 className="w-4 h-4" />
                         <span>Suas respostas foram melhoradas!</span>
                       </>
                     ) : enhanceResult === 'error' ? (
                       <>
                         <span className="material-symbols-outlined text-lg">warning</span>
                         <span>Erro — tente novamente</span>
                       </>
                     ) : (
                       <>
                         <span className="material-symbols-outlined text-lg">auto_fix_high</span>
                         <span>Melhorar Tudo com IA</span>
                       </>
                     )}
                   </motion.button>
                 )}

                 {/* Success Toast after AI enhance */}
                 <AnimatePresence>
                   {enhanceResult === 'success' && (
                     <motion.div
                       initial={{ opacity: 0, y: 10 }}
                       animate={{ opacity: 1, y: 0 }}
                       exit={{ opacity: 0, y: -10 }}
                       className="mt-4 p-4 rounded-2xl bg-emerald-500/10 border border-emerald-500/20 relative z-10"
                     >
                       <p className="text-sm text-emerald-300 text-center font-medium">
                         Pronto! Suas respostas foram melhoradas. Seus próximos textos e roteiros vão ficar ainda melhores.
                       </p>
                     </motion.div>
                   )}
                 </AnimatePresence>

                 {/* CTA: Next step after 100% */}
                 {completion === 100 && enhanceResult !== 'success' && (
                   <motion.div
                     initial={{ opacity: 0, y: 10 }}
                     animate={{ opacity: 1, y: 0 }}
                     transition={{ delay: 0.3 }}
                     className="mt-6 p-6 rounded-2xl bg-gradient-to-r from-emerald-500/10 to-[#0ea5e9]/10 border border-emerald-500/20 text-center relative z-10"
                   >
                     <span className="material-symbols-outlined text-[32px] text-emerald-400 mb-2 block">rocket_launch</span>
                     <h4 className="text-lg font-black text-white mb-1">Perfil Completo! 🚀</h4>
                     <p className="text-sm text-slate-400 mb-5">
                       Agora que temos todas as suas informações, vamos criar seu primeiro conteúdo.
                     </p>
                     <div className="flex flex-col sm:flex-row gap-3 justify-center">
                       <Link
                         href="/jornada"
                         className="inline-flex items-center justify-center gap-2 px-6 py-3 rounded-xl bg-gradient-to-r from-emerald-500 to-[#0ea5e9] text-white font-bold text-sm hover:opacity-90 transition-opacity active:scale-[0.97]"
                       >
                         <span className="material-symbols-outlined text-lg">explore</span>
                         Ir para a Jornada de Conteúdo
                       </Link>
                       <Link
                         href="/prompts"
                         className="inline-flex items-center justify-center gap-2 px-6 py-3 rounded-xl bg-white/5 border border-white/10 text-white font-bold text-sm hover:bg-white/10 transition-colors active:scale-[0.97]"
                       >
                         <span className="material-symbols-outlined text-lg">auto_awesome</span>
                         Gerar meu primeiro Roteiro
                       </Link>
                     </div>
                   </motion.div>
                 )}
              </motion.div>

              {/* Form Sections */}
              {sections.map((sectionKey, si) => {
                const meta = SECTION_META[sectionKey]
                const fields = PROFILE_FIELDS.filter(f => f.section === sectionKey)

                return (
                  <motion.div 
                    key={sectionKey} 
                    initial={{ opacity: 0, y: 20 }} 
                    animate={{ opacity: 1, y: 0 }} 
                    transition={{ delay: 0.2 + (si * 0.1) }} 
                    className="glass-card rounded-3xl p-8 border border-white/5"
                  >
                    <div className="flex items-center gap-4 mb-8">
                      <div className="size-12 rounded-xl bg-[#0ea5e9]/10 flex items-center justify-center border border-[#0ea5e9]/20 shadow-inner">
                        <span className="material-symbols-outlined text-[#0ea5e9] text-2xl">{meta.icon}</span>
                      </div>
                      <div>
                        <h3 className="font-bold text-xl text-white tracking-tight">{meta.title}</h3>
                        <p className="text-sm text-slate-400">{meta.desc}</p>
                      </div>
                    </div>

                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      {fields.map(field => {
                        const fieldValue = profile?.[field.id] as string || ''
                        const status = saveStatus[field.id] || 'idle'
                        const isTextarea = field.type === 'textarea'
                        return (
                          <div key={field.id} className={`space-y-2 ${isTextarea ? 'md:col-span-2' : ''}`}>
                            <div className="flex items-center justify-between">
                              <label htmlFor={field.id} className="text-xs font-bold text-slate-400 uppercase tracking-widest ml-1">
                                {field.label}
                              </label>
                              <div className="h-4 flex items-center gap-2">
                                {status === 'saving' && <span className="text-[10px] text-slate-500 flex items-center gap-1 uppercase tracking-widest font-bold"><Loader2 className="w-3 h-3 animate-spin" />Salvando</span>}
                                {status === 'saved' && <span className="text-[10px] text-[#0ea5e9] flex items-center gap-1 uppercase tracking-widest font-bold"><CheckCircle2 className="w-3 h-3" />Salvo</span>}
                                {status === 'error' && <span className="text-[10px] text-red-400 flex items-center gap-1 uppercase tracking-widest font-bold">Erro ao salvar</span>}
                              </div>
                            </div>

                            <div className="group relative">
                              <div className="absolute inset-0 bg-white/5 rounded-2xl opacity-0 group-focus-within:opacity-100 transition-opacity pointer-events-none border border-[#0ea5e9]/50"></div>
                              {isTextarea ? (
                                <Textarea
                                  id={field.id}
                                  placeholder={field.placeholder}
                                  value={fieldValue}
                                  onChange={e => handleFieldChange(field.id, e.target.value)}
                                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-4 focus-visible:ring-0 focus-visible:border-[#0ea5e9] outline-none transition-all resize-none text-white text-sm leading-relaxed min-h-[100px] relative z-10 placeholder:text-slate-600"
                                  rows={4}
                                />
                              ) : (
                                <Input
                                  id={field.id}
                                  placeholder={field.placeholder}
                                  value={fieldValue}
                                  onChange={e => handleFieldChange(field.id, e.target.value)}
                                  className="w-full bg-white/5 border border-white/10 rounded-2xl px-5 py-6 h-auto focus-visible:ring-0 focus-visible:border-[#0ea5e9] outline-none transition-all text-white text-sm relative z-10 placeholder:text-slate-600"
                                />
                              )}
                            </div>


                          </div>
                        )
                      })}
                    </div>
                  </motion.div>
                )
              })}
            </div>

            {/* Right Side: Extras */}
            <div className="lg:col-span-4 space-y-8">

              {/* Help/Tips Card */}
              <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.3 }} className="bg-gradient-to-br from-[#0ea5e9]/20 to-indigo-900/10 rounded-3xl p-8 border border-[#0ea5e9]/20 relative overflow-hidden group">
                 <div className="relative z-10">
                    <h4 className="text-lg font-bold text-white mb-2 flex items-center gap-2">
                       <span className="material-symbols-outlined text-[#0ea5e9]">lightbulb</span>
                       Como preencher?
                    </h4>
                    <p className="text-sm text-slate-300 leading-relaxed mb-6">
                       Essas informações são usadas para criar textos feitos sob medida para você.
                       Escreva do jeito mais natural possível, como se estivesse explicando pra um amigo.
                    </p>
                    <ul className="space-y-3 text-sm text-slate-400">
                       <li className="flex gap-2 items-start"><span className="text-[#0ea5e9] mt-0.5">•</span> Imagine que está contando sobre seu trabalho para alguém que acabou de conhecer.</li>
                       <li className="flex gap-2 items-start"><span className="text-[#0ea5e9] mt-0.5">•</span> Quanto mais detalhes sobre o seu público, melhores ficam os textos.</li>
                       <li className="flex gap-2 items-start"><span className="text-[#0ea5e9] mt-0.5">•</span> Use o botão <strong className="text-violet-400">"Melhorar Tudo com IA"</strong> para deixar suas respostas mais completas.</li>
                       <li className="flex gap-2 items-start"><span className="text-[#0ea5e9] mt-0.5">•</span> Você pode mudar essas informações quando quiser — seus textos se atualizam sozinhos!</li>
                    </ul>
                 </div>
              </motion.div>

              {/* Status Indicator */}
              <motion.div initial={{ opacity: 0, x: 20 }} animate={{ opacity: 1, x: 0 }} transition={{ delay: 0.4 }} className="glass-card rounded-3xl p-8 border border-white/5">
                 <h4 className="text-sm font-bold text-white mb-4 uppercase tracking-widest flex items-center gap-2">
                    <span className="material-symbols-outlined text-slate-500">cloud_done</span>
                    Salvamento
                 </h4>

                 <div className="space-y-4">
                    <div>
                       <div className="flex justify-between text-xs font-medium text-slate-400 mb-1">
                          <span>Suas informações</span>
                          <span className="text-[#0ea5e9]">Ativo</span>
                       </div>
                       <div className="w-full h-1.5 bg-white/5 rounded-full overflow-hidden">
                          <div className="h-full w-full bg-[#0ea5e9] shadow-[0_0_10px_rgba(14,165,233,0.5)]"></div>
                       </div>
                    </div>
                    <p className="text-xs text-slate-500">
                       Tudo é salvo automaticamente enquanto você digita. Não precisa se preocupar em perder nada.
                    </p>
                 </div>
              </motion.div>

            </div>
          </div>
        </div>
      </main>
    </>
  )
}

'use client'

import { use, useState } from 'react'

import { useProfile } from '@/hooks/use-profile'
import { PROMPT_CONFIGS, type PromptType } from '@/types/prompt'
import { generateClarezaPrompt } from '@/lib/prompts/clareza'
import { generatePersonaPrompt } from '@/lib/prompts/persona'
import { generateIdeiasPrompt } from '@/lib/prompts/ideias'
import { generateRoteiroPrompt } from '@/lib/prompts/roteiro'
import { generateVendasPrompt } from '@/lib/prompts/vendas'
import { Textarea } from '@/components/ui/textarea'
import { cn } from '@/lib/utils'
import { motion } from 'framer-motion'
import Link from 'next/link'

const generators: Record<PromptType, (p: Parameters<typeof generateClarezaPrompt>[0]) => string> = {
  clareza: generateClarezaPrompt,
  persona: generatePersonaPrompt,
  ideias: generateIdeiasPrompt,
  roteiro: generateRoteiroPrompt,
  vendas: generateVendasPrompt,
}

const NEXT_PROMPT: Record<PromptType, PromptType | null> = {
  clareza: 'persona',
  persona: 'ideias',
  ideias: 'roteiro',
  roteiro: 'vendas',
  vendas: null,
}

export default function PromptPage({ params }: { params: Promise<{ tipo: string }> }) {
  const resolvedParams = use(params)
  const tipo = resolvedParams.tipo as PromptType
  const config = PROMPT_CONFIGS[tipo]
  const { profile, loading, updateField } = useProfile()
  const [prompt, setPrompt] = useState('')
  const [generated, setGenerated] = useState(false)
  const [copied, setCopied] = useState(false)

  if (!config) {
    return (
      <>
        <div className="p-8 text-center mt-20">
          <p className="text-slate-400 text-lg">Este tipo de prompt não existe.</p>
          <Link href="/" className="text-[#0ea5e9] text-sm mt-4 font-bold hover:underline inline-block">Voltar ao início</Link>
        </div>
      </>
    )
  }

  const checkDependencies = () => {
    for (const dep of config.dependencias) {
      const depConfig = PROMPT_CONFIGS[dep]
      const responseField = `resposta${depConfig.numero}` as keyof typeof profile
      if (!profile?.[responseField]) {
        return { met: false, missing: dep }
      }
    }
    return { met: true, missing: null }
  }

  const handleGenerate = () => {
    if (!profile) return
    const deps = checkDependencies()
    if (!deps.met) return

    const generator = generators[tipo]
    const result = generator(profile)
    setPrompt(result)
    setGenerated(true)
  }

  const handleCopy = async () => {
    try {
      await navigator.clipboard.writeText(prompt)
    } catch {
      // Fallback for non-HTTPS environments
      const textarea = document.createElement('textarea')
      textarea.value = prompt
      textarea.style.position = 'fixed'
      textarea.style.opacity = '0'
      document.body.appendChild(textarea)
      textarea.select()
      document.execCommand('copy')
      document.body.removeChild(textarea)
    }
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <span className="material-symbols-outlined animate-spin text-[#0ea5e9] text-4xl">autorenew</span>
      </div>
    )
  }

  const deps = checkDependencies()

  return (
    <>
      <main className="p-6 lg:p-8 max-w-7xl mx-auto w-full grid grid-cols-1 xl:grid-cols-2 gap-8 relative z-10">

        {/* Left Column: Form */}
        <div className="flex flex-col gap-6">
          <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }}>
            <div className="flex items-center gap-4 mb-2">
              <span className="text-4xl">{config.icone}</span>
              <h1 className="text-3xl lg:text-4xl font-extrabold tracking-tight bg-clip-text text-transparent bg-gradient-to-r from-white to-slate-400">
                Passo {config.numero}: {config.titulo}
              </h1>
            </div>
            <p className="text-slate-400">{config.descricao}</p>
          </motion.div>

          <motion.div initial={{ opacity: 0, scale: 0.98 }} animate={{ opacity: 1, scale: 1 }} transition={{ delay: 0.1 }} className="glass-card p-6 lg:p-8 rounded-xl flex flex-col gap-6 shadow-2xl shadow-[#0ea5e9]/10 border border-white/5">

            {/* Dependencies Warning */}
            {!deps.met && deps.missing && (
              <div className="bg-amber-500/10 border border-amber-500/20 rounded-xl p-6">
                <div className="flex items-start gap-3">
                  <span className="material-symbols-outlined text-amber-500 shrink-0">warning</span>
                  <div>
                    <p className="text-sm font-bold text-amber-400">
                      Faça o Passo {PROMPT_CONFIGS[deps.missing].numero} ({PROMPT_CONFIGS[deps.missing].titulo}) antes
                    </p>
                    <p className="text-xs text-slate-400 mt-1 mb-3">
                      Cole a resposta que o ChatGPT te deu no campo abaixo.
                    </p>
                    <Link href={`/prompts/${deps.missing}`} className="text-xs text-[#0ea5e9] font-bold hover:underline flex items-center gap-1 w-max">
                      Ir para Prompt {PROMPT_CONFIGS[deps.missing].numero} <span className="material-symbols-outlined text-[14px]">arrow_right_alt</span>
                    </Link>
                  </div>
                </div>
              </div>
            )}

            <div className="space-y-6">
              {/* Previous Response Fields */}
              {config.dependencias.map((dep, index) => {
                const depConfig = PROMPT_CONFIGS[dep]
                const fieldKey = `resposta${depConfig.numero}`
                const value = (profile as Record<string, string | null>)?.[fieldKey] || ''
                const isSatisfied = !!value

                return (
                  <div key={dep}>
                    <label className="text-sm font-semibold text-slate-300 mb-2 flex items-center gap-2 uppercase tracking-wider">
                      {isSatisfied ? <span className="material-symbols-outlined text-emerald-500 text-[18px]">check_circle</span> : <span className="material-symbols-outlined text-amber-500 text-[18px]">error</span>}
                      Resposta do Passo {depConfig.numero} ({depConfig.titulo})
                    </label>
                    <Textarea
                      placeholder={`Cole aqui a resposta do ChatGPT do Passo ${depConfig.numero}...`}
                      value={value}
                      onChange={e => updateField(fieldKey, e.target.value)}
                      className="w-full bg-white/5 border border-white/10 rounded-lg p-4 text-slate-100 placeholder:text-slate-500 focus:ring-2 focus:ring-[#0ea5e9] outline-none resize-none transition-all shadow-inner min-h-[100px]"
                    />
                  </div>
                )
              })}

              {/* Extra Field (Roteiro / Vendas) */}
              {config.campoExtra && (
                <div>
                  <label className="text-sm font-semibold text-slate-300 mb-2 block uppercase tracking-wider">
                    {config.campoExtra.label}
                  </label>
                  <Textarea
                    placeholder={config.campoExtra.placeholder}
                    value={(profile as Record<string, string | null>)?.[config.campoExtra.id] || ''}
                    onChange={e => updateField(config.campoExtra!.id, e.target.value)}
                    className="w-full bg-white/5 border border-white/10 rounded-lg p-4 text-slate-100 placeholder:text-slate-500 focus:ring-2 focus:ring-[#0ea5e9] outline-none resize-none transition-all shadow-inner min-h-[100px]"
                  />
                </div>
              )}
            </div>

            <button 
              onClick={handleGenerate}
              disabled={!deps.met}
              className="shimmer-btn w-full py-4 rounded-xl flex items-center justify-center gap-3 text-white font-bold text-lg disabled:opacity-50 disabled:cursor-not-allowed group transition-transform hover:scale-[1.02] active:scale-95"
            >
              <span className="material-symbols-outlined group-hover:scale-110 transition-transform">auto_awesome</span>
              {generated ? 'Gerar de Novo' : `Gerar Meu Texto`}
            </button>
          </motion.div>

          {/* Paste Current Response section */}
          {generated && (
            <motion.div initial={{ opacity: 0, y: 10 }} animate={{ opacity: 1, y: 0 }} className="glass-card rounded-xl p-6 border-l-4 border-l-[#0ea5e9]">
              <label className="text-sm font-bold flex items-center gap-2 text-white mb-2 uppercase tracking-wide">
                <span className="material-symbols-outlined text-[#0ea5e9]">chat</span>
                Resposta do ChatGPT
              </label>
              <p className="text-xs text-slate-400 mb-4">
                Copie o texto acima, cole no ChatGPT, e depois cole aqui a resposta que ele te der.
              </p>
              <Textarea
                placeholder="Cole a resposta final aqui..."
                value={(profile as Record<string, string | null>)?.[`resposta${config.numero}`] || ''}
                onChange={e => updateField(`resposta${config.numero}`, e.target.value)}
                className="w-full bg-white/5 border border-white/10 rounded-lg p-4 text-slate-100 placeholder:text-slate-500 focus:ring-2 focus:ring-[#0ea5e9] outline-none resize-none transition-all min-h-[140px]"
              />

              {/* Next Prompt Button — appears when response is pasted */}
              {((profile as Record<string, string | null>)?.[`resposta${config.numero}`] || '').trim().length > 0 && (
                <motion.div
                  initial={{ opacity: 0, y: 8 }}
                  animate={{ opacity: 1, y: 0 }}
                  transition={{ duration: 0.4, ease: [0.16, 1, 0.3, 1] }}
                  className="mt-5"
                >
                  {NEXT_PROMPT[tipo] ? (
                    <Link
                      href={`/prompts/${NEXT_PROMPT[tipo]}`}
                      className="shimmer-btn w-full py-4 rounded-xl flex items-center justify-center gap-3 text-white font-bold text-lg group transition-transform hover:scale-[1.02] active:scale-95"
                    >
                      <span>Próximo Passo: {PROMPT_CONFIGS[NEXT_PROMPT[tipo]!].titulo}</span>
                      <span className="material-symbols-outlined text-xl group-hover:translate-x-1 transition-transform">arrow_forward</span>
                    </Link>
                  ) : (
                    <Link
                      href="/prompts"
                      className="w-full py-4 rounded-xl flex items-center justify-center gap-3 text-white font-bold text-lg bg-gradient-to-r from-emerald-500 to-green-400 transition-transform hover:scale-[1.02] active:scale-95 shadow-lg shadow-emerald-500/20"
                    >
                      <span className="material-symbols-outlined text-xl">check_circle</span>
                      <span>Tudo Pronto! 🎉</span>
                    </Link>
                  )}
                </motion.div>
              )}
            </motion.div>
          )}

        </div>

        {/* Right Column: Terminal Result */}
        <div className="flex flex-col h-full min-h-[600px] xl:max-h-[calc(100vh-120px)] xl:sticky xl:top-[100px]">
          <div className="flex items-center justify-between mb-4">
            <span className="text-xs font-bold uppercase tracking-[0.2em] text-slate-500">Seu Texto Gerado</span>
            <div className="flex gap-2">
              <span className={cn(
                "px-2 py-1 text-[10px] font-bold rounded border transition-colors",
                generated ? "bg-green-500/10 text-green-500 border-green-500/20" : "bg-amber-500/10 text-amber-500 border-amber-500/20"
              )}>
                {generated ? 'PRONTO' : 'ESPERANDO'}
              </span>
              <span className="px-2 py-1 bg-[#0ea5e9]/10 text-[#0ea5e9] text-[10px] font-bold rounded border border-[#0ea5e9]/20">V2.4.0</span>
            </div>
          </div>

          <div className="bg-[#0a0a0a] border border-white/10 rounded-xl flex flex-col flex-1 overflow-hidden shadow-2xl">
            {/* Mac-style Terminal Header */}
            <div className="bg-white/5 px-4 py-3 flex items-center justify-between border-b border-white/5">
              <div className="flex gap-2">
                <div className="w-3 h-3 rounded-full bg-[#ff5f56]"></div>
                <div className="w-3 h-3 rounded-full bg-[#ffbd2e]"></div>
                <div className="w-3 h-3 rounded-full bg-[#27c93f]"></div>
              </div>
              <div className="text-[10px] text-slate-500 font-mono">gerador_texto_{config.tipo}</div>
              <button onClick={handleCopy} disabled={!generated} className="flex items-center gap-2 text-slate-400 hover:text-white transition-colors disabled:opacity-50">
                <span className="material-symbols-outlined text-sm">{copied ? 'check' : 'content_copy'}</span>
                <span className="text-[10px] font-bold uppercase">{copied ? 'Copiado' : 'Copiar'}</span>
              </button>
            </div>

            {/* Terminal Content */}
            <div className="p-6 font-mono text-sm leading-relaxed overflow-y-auto flex-1 text-slate-300">
              {generated ? (
                 <div className="space-y-4">
                   <p className="text-[#0ea5e9]">✅ Texto gerado!</p>
                   <p className="text-emerald-400"># Passo {config.numero} ({config.titulo}) — copie e cole no ChatGPT</p>
                   <pre className="whitespace-pre-wrap break-words mt-4 font-sans text-base">{prompt}</pre>
                 </div>
              ) : (
                <div className="flex flex-col items-center justify-center h-full opacity-50 space-y-4 text-center">
                   <span className="material-symbols-outlined text-4xl">edit_note</span>
                   <p>Clique em "Gerar Meu Texto" para começar</p>
                </div>
              )}
            </div>

            <div className="p-4 border-t border-white/5 bg-white/[0.02]">
              <div className="flex items-center gap-3">
                <span className="text-[#0ea5e9] font-bold">➜</span>
                <span className="text-slate-500 text-xs">Copie o texto acima e cole no ChatGPT</span>
              </div>
            </div>
          </div>
        </div>

      </main>
    </>
  )
}

