  { label: 'Ganchos Virais', href: '/ganchos', icon: 'anchor', badge: '50', section: 'Ferramentas' },
  { label: 'Stories', href: '/stories', icon: 'video_camera_front', badge: '🔥', badgeHot: true, section: 'Ferramentas' },
  { label: 'Rotina', href: '/rotina', icon: 'calendar_today', section: 'Ferramentas' },
  { label: 'Analisador', href: '/bio-analyzer', icon: 'monitoring', badge: 'Novo', section: 'Ferramentas' },
  { label: 'Calculadora', href: '/calculadora', icon: 'calculate', badge: 'Novo', section: 'Ferramentas' },
]

interface SidebarProps {
  className?: string
}

export function Sidebar({ className = '' }: SidebarProps) {
  const pathname = usePathname()
  const supabase = createClient()
  const { profile } = useProfile()

  const handleLogout = async () => {
    await supabase.auth.signOut()
    window.location.href = '/login'
  }

  const getDisplayName = () => {
    if (profile?.nome_completo) return profile.nome_completo
    if (!profile?.email) return 'Usuário'
    return profile.email.split('@')[0].split('.')[0].replace(/^\w/, c => c.toUpperCase())
  }

  const getInitials = () => {
    const name = profile?.nome_completo || profile?.email?.split('@')[0] || 'U'
    const parts = name.split(/[\s.]+/)
    if (parts.length >= 2) return (parts[0][0] + parts[1][0]).toUpperCase()
    return name.substring(0, 2).toUpperCase()
  }

  return (
    <aside className={cn("hidden lg:flex w-20 lg:w-64 flex-col border-r border-white/5 bg-black/50 backdrop-blur-md shrink-0 transition-all z-40", className)}>
      <div className="p-6 flex items-center gap-3">
        <div className="size-10 bg-[#0ea5e9] rounded-lg flex items-center justify-center text-white shrink-0 shadow-lg shadow-[#0ea5e9]/20">
          <span className="material-symbols-outlined">map</span>
        </div>
        <span className="font-bold text-lg tracking-tight hidden lg:block text-white">Mapa do Engajamento</span>
      </div>

      <nav className="flex-1 px-4 space-y-2 py-4 overflow-y-auto">
        {NAV_ITEMS.map(item => {
          const isActive = pathname === item.href || (item.href !== '/' && pathname.startsWith(item.href))

          return (
            <Link
              key={item.href}
              href={item.href}
              className={cn(
                "flex items-center gap-4 px-3 py-3 rounded-xl transition-all",
                isActive 
                  ? "bg-[#0ea5e9]/20 text-[#0ea5e9]"
                  : "text-slate-400 hover:bg-white/5 hover:text-white"
              )}
            >
              <span className={cn("material-symbols-outlined", isActive && "fill-1")}>
                {item.icon}
              </span>
              <span className="font-medium hidden lg:block flex-1 whitespace-nowrap">{item.label}</span>

              {item.badge && (
                <span className={cn(
                  "hidden lg:block px-2 py-0.5 rounded-full text-[10px] font-bold shrink-0",
                  item.badgeHot
                    ? "bg-gradient-to-r from-amber-500 to-red-500 text-white animate-pulse"
                    : "bg-white/10 text-white/70"
                )}>
                  {item.badge}
                </span>
              )}
            </Link>
          )
        })}
      </nav>

      <div className="p-4 mt-auto space-y-4">
        {/* Support Box */}
        <div className="bg-white/5 p-4 rounded-xl hidden lg:block border border-white/5">
          <p className="text-xs font-semibold text-[#0ea5e9] uppercase tracking-widest mb-2">Suporte</p>
          <p className="text-xs text-slate-400 leading-relaxed">Precisa de ajuda com sua estratégia?</p>
          <button className="mt-3 text-xs font-bold text-white flex items-center gap-1 hover:underline">
            Abrir Ticket <span className="material-symbols-outlined text-[14px]">arrow_forward</span>
          </button>
        </div>

        {/* User Profile + Logout */}
        <div className="flex items-center gap-3 lg:px-2 pt-2">
          {/* Avatar */}
          <Link href="/perfil" className="shrink-0">
            <div className="size-10 rounded-full overflow-hidden ring-2 ring-[#0ea5e9]/20 hover:ring-[#0ea5e9]/50 transition-all">
              {profile?.avatar_url ? (
                <img src={profile.avatar_url} alt="Avatar" className="w-full h-full object-cover" />
              ) : (
                <div className="w-full h-full bg-gradient-to-tr from-[#0ea5e9] to-indigo-500 flex items-center justify-center">
                  <span className="text-xs font-black text-white">{getInitials()}</span>
                </div>
              )}
            </div>
          </Link>

          {/* Name + Sair */}
          <div className="hidden lg:flex flex-1 items-center justify-between min-w-0">
            <Link href="/perfil" className="truncate">
              <p className="text-sm font-bold text-white truncate hover:text-[#0ea5e9] transition-colors">{getDisplayName()}</p>
            </Link>
            <button
              onClick={handleLogout}
              className="text-xs font-bold text-slate-500 hover:text-red-400 transition-colors px-2 py-1 rounded-lg hover:bg-red-500/10 shrink-0"
            >
              Sair
            </button>
          </div>
        </div>
      </div>
    </aside>
  )
}

'use client'

import { useState, useRef, useEffect } from 'react'
import { motion, AnimatePresence } from 'framer-motion'
import Link from 'next/link'
import { Notification, TYPE_COLORS, TYPE_LABELS } from '@/data/notifications'

interface NotificationPanelProps {
  notifications: Notification[]
  unreadCount: number
  onRead: (id: string) => void
  onReadAll: () => void
}

export function NotificationPanel({ 
  notifications, 
  unreadCount, 
  onRead, 
  onReadAll 
}: NotificationPanelProps) {
  const [isOpen, setIsOpen] = useState(false)
  const panelRef = useRef<HTMLDivElement>(null)

  // Close on click outside
  useEffect(() => {
    function handleClickOutside(e: MouseEvent) {
      if (panelRef.current && !panelRef.current.contains(e.target as Node)) {
        setIsOpen(false)
      }
    }
    if (isOpen) {
      document.addEventListener('mousedown', handleClickOutside)
      return () => document.removeEventListener('mousedown', handleClickOutside)
    }
  }, [isOpen])

  // Close on Escape
  useEffect(() => {
    function handleEsc(e: KeyboardEvent) {
      if (e.key === 'Escape') setIsOpen(false)
    }
    if (isOpen) {
      document.addEventListener('keydown', handleEsc)
      return () => document.removeEventListener('keydown', handleEsc)
    }
  }, [isOpen])

  const handleNotificationClick = (n: Notification) => {
    onRead(n.id)
    setIsOpen(false)
  }

  const formatTime = (timestamp: number) => {
    const diff = Date.now() - timestamp
    const mins = Math.floor(diff / 60000)
    if (mins < 1) return 'Agora'
    if (mins < 60) return `${mins}min`
    const hours = Math.floor(mins / 60)
    if (hours < 24) return `${hours}h`
    return `${Math.floor(hours / 24)}d`
  }

  return (
    <div className="relative" ref={panelRef}>
      {/* Bell Button */}
      <button 
        onClick={() => setIsOpen(!isOpen)}
        className={`size-9 sm:size-10 rounded-full flex items-center justify-center transition-all border relative ${
          isOpen 
            ? 'bg-[#0ea5e9]/20 text-[#0ea5e9] border-[#0ea5e9]/30' 
            : 'bg-white/5 text-slate-300 hover:text-white border-white/10 hover:border-white/20'
        }`}
      >
        <span className="material-symbols-outlined text-xl">notifications</span>

        {/* Badge */}
        {unreadCount > 0 && (
          <span className="absolute -top-1 -right-1 size-5 rounded-full bg-red-500 text-white text-[10px] font-black flex items-center justify-center shadow-lg shadow-red-500/30 animate-pulse">
            {unreadCount > 9 ? '9+' : unreadCount}
          </span>
        )}
      </button>

      {/* Dropdown Panel */}
      <AnimatePresence>
        {isOpen && (
          <motion.div
            initial={{ opacity: 0, y: 8, scale: 0.96 }}
            animate={{ opacity: 1, y: 0, scale: 1 }}
            exit={{ opacity: 0, y: 8, scale: 0.96 }}
            transition={{ duration: 0.15 }}
            className="absolute right-0 top-full mt-2 w-[340px] sm:w-[380px] max-h-[70vh] rounded-2xl border border-white/10 bg-[#0a0a0a]/95 backdrop-blur-xl shadow-2xl shadow-black/50 overflow-hidden z-50 flex flex-col"
          >
            {/* Header */}
            <div className="px-5 py-4 border-b border-white/5 flex items-center justify-between shrink-0">
              <div className="flex items-center gap-2">
                <span className="material-symbols-outlined text-[#0ea5e9] text-xl">notifications</span>
                <h3 className="font-bold text-white text-sm">Notificações</h3>
                {unreadCount > 0 && (
                  <span className="text-[10px] font-bold bg-[#0ea5e9]/15 text-[#0ea5e9] px-2 py-0.5 rounded-full">
                    {unreadCount} novas
                  </span>
                )}
              </div>
              {unreadCount > 0 && (
                <button
                  onClick={onReadAll}
                  className="text-xs text-slate-500 hover:text-[#0ea5e9] transition-colors font-medium"
                >
                  Marcar todas como lidas
                </button>
              )}
            </div>

            {/* Notification List */}
            <div className="overflow-y-auto flex-1 custom-scrollbar">
              {notifications.length === 0 ? (
                <div className="py-12 text-center">
                  <span className="material-symbols-outlined text-4xl text-slate-600 mb-3 block">notifications_off</span>
                  <p className="text-sm text-slate-500">Nenhuma notificação no momento.</p>
                </div>
              ) : (
                <div className="divide-y divide-white/5">
                  {notifications.map((n) => {
                    const typeColor = TYPE_COLORS[n.type]
                    const typeLabel = TYPE_LABELS[n.type]

                    const content = (
                      <div
                        className={`px-5 py-4 flex gap-3.5 transition-colors cursor-pointer group ${
                          n.read 
                            ? 'opacity-60 hover:opacity-80' 
                            : 'hover:bg-white/[0.03]'
                        }`}
                        onClick={() => handleNotificationClick(n)}
                      >
                        {/* Icon */}
                        <div 
                          className="size-10 rounded-xl flex items-center justify-center shrink-0 border"
                          style={{ 
                            backgroundColor: `${typeColor}15`,
                            borderColor: `${typeColor}30`,
                          }}
                        >
                          <span 
                            className="material-symbols-outlined text-lg"
                            style={{ color: typeColor }}
                          >
                            {n.icon}
                          </span>
                        </div>

                        {/* Content */}
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 mb-1">
                            <span 
                              className="text-[9px] font-bold uppercase tracking-widest px-1.5 py-0.5 rounded"
                              style={{ 
                                backgroundColor: `${typeColor}15`,
                                color: typeColor,
                              }}
                            >
                              {typeLabel}
                            </span>
                            <span className="text-[10px] text-slate-600 ml-auto shrink-0">
                              {formatTime(n.timestamp)}
                            </span>
                          </div>
                          <h4 className={`text-sm font-bold mb-0.5 truncate ${n.read ? 'text-slate-400' : 'text-white'}`}>
                            {n.title}
                          </h4>
                          <p className="text-xs text-slate-500 line-clamp-2 leading-relaxed">
                            {n.message}
                          </p>
                        </div>

                        {/* Unread dot */}
                        {!n.read && (
                          <div className="shrink-0 mt-2">
                            <div className="size-2 rounded-full bg-[#0ea5e9] shadow-lg shadow-[#0ea5e9]/50" />
                          </div>
                        )}
                      </div>
                    )

                    if (n.href) {
                      return (
                        <Link key={n.id} href={n.href} className="block">
                          {content}
                        </Link>
                      )
                    }

                    return <div key={n.id}>{content}</div>
                  })}
                </div>
              )}
            </div>

            {/* Footer */}
            <div className="px-5 py-3 border-t border-white/5 shrink-0">
              <p className="text-[10px] text-slate-600 text-center">
                As notificações são geradas com base no seu progresso na plataforma.
              </p>
            </div>
          </motion.div>
        )}
      </AnimatePresence>
    </div>
  )
}

import type { Nivel, Achievement } from '@/types/gamification'

export const NIVEIS: Nivel[] = [
  { nivel: 1, xp_min: 0, xp_max: 100, titulo: 'Iniciante', cor: '#94a3b8', icone: '🌱' },
  { nivel: 2, xp_min: 100, xp_max: 300, titulo: 'Aprendiz', cor: '#22c55e', icone: '📗' },
  { nivel: 3, xp_min: 300, xp_max: 600, titulo: 'Criador', cor: '#3b82f6', icone: '🎨' },
  { nivel: 4, xp_min: 600, xp_max: 1000, titulo: 'Expert', cor: '#8b5cf6', icone: '🔮' },
  { nivel: 5, xp_min: 1000, xp_max: 1500, titulo: 'Mestre', cor: '#f59e0b', icone: '👑' },
  { nivel: 6, xp_min: 1500, xp_max: 2500, titulo: 'Viral Master', cor: '#ef4444', icone: '🔥' },
  { nivel: 7, xp_min: 2500, xp_max: 10000, titulo: 'Lenda', cor: '#ec4899', icone: '🏆' },
]

export function getNivelByXP(xp: number): Nivel {
  return NIVEIS.find(n => xp >= n.xp_min && xp < n.xp_max) || NIVEIS[NIVEIS.length - 1]
}

export function getProgressoNivel(xp: number): number {
  const nivel = getNivelByXP(xp)
  const xpNoNivel = xp - nivel.xp_min
  const xpTotalNivel = nivel.xp_max - nivel.xp_min
  return Math.round((xpNoNivel / xpTotalNivel) * 100)
}
